#include <iostream>
#include <vector>
#include <omp.h>

void scan(const int* input, int* output, int n) {
    output[0] = 0;
    #pragma omp parallel for
    for (int i = 1; i < n; i++) {
        int sum = 0;
        for (int j = 0; j < i; j++) {
            sum += input[j];
        }
        output[i] = sum;
    }
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> input(n);
    std::vector<int> output(n);

    for (int i = 0; i < n; i++) {
        std::cin >> input[i];
    }

    scan(input.data(), output.data(), n);

    for (int i = 0; i < n; i++) {
        std::cout << output[i] << std::endl;
    }

    return 0;
}
